var e=JSON.parse(`[{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"어둠 속에서, 무엇인가가 울부짖는 소리가 들렸다.","JPN":"暗闇の中で、何かが泣き叫ぶ声を聞いた。","ENG":"In darkness, I hear the cry of something.","TWN":"我聽見，黑暗中有什麼東西在哭喊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"만족하면서도 아쉬워하는 듯한.","JPN":"満足しているような、残念がっているような。","ENG":"A cry that was...","TWN":"似是滿足又些許遺憾的感覺。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"그런 울음소리였다.","JPN":"そんな泣き声だった。","ENG":"Content, yet sad.","TWN":"就是那樣的哭喊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"저는 알고 있습니다.","JPN":"私は知っていますよ。","ENG":"I know.","TWN":"我知道。"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"당신의 노력과, 죄와, 절망을.","JPN":"君の努力と、罪と、絶望を。","ENG":"Your efforts, sins, and despair.","TWN":"那是你的努力、罪惡、絕望，"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 그럼에도 놓지 못했던 희망을.","JPN":"そして、それでも結局諦められなかった希望を。","ENG":"Nevertheless, you never let go of hope.","TWN":"還有即便如此也沒放棄的希望。"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"나는……. 아직 죽지 않았군.","JPN":"私は……まだ死んでいないのか。","ENG":"I'm... not dead yet.","TWN":"我……還沒死啊。"},"stage":{"bg":"VOID","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"정확히는 영원에 가깝게 죽어가고 있었죠.","JPN":"正確にはほぼ永遠の死に向かっていました。","ENG":"To be exact, you are dying close to eternity.","TWN":"準確地說，你快要死掉了，永遠地。"},"stage":{"bg":"VOID","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"허수공간에서 관측자가 부재하게 되면 그 순간에 영원히 갇힐 수도 있으니까요.","JPN":"虚数空間で観測者が不在になると、その瞬間に永遠に閉じ込められることもありますからね。","ENG":"When the observer of the imaginary space is absent, you will be trapped in here forever.","TWN":"一旦虛數空間裡沒有了觀測者，你就有可能永遠被困在那一瞬間。"},"stage":{"bg":"VOID","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"……누구냐, 너는.","JPN":"……誰だ、お前は。","ENG":"...Who are you?","TWN":"……你是誰。"},"stage":{"bg":"VOID","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"혹시나 해서 말씀드리지만, 저에 대해 물어보셔도 대답해 드릴 수 없습니다.","JPN":"念のために言っておきますが、私について聞かれてもお答えできません。","ENG":"Fair warning. I cannot answer the questions you have about me.","TWN":"我話先說在前頭，即使你問了關於我的事，我也不能回答你。"},"stage":{"bg":"VOID","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"당신이 보고 계실 저는 단파 통신으로 보낸 홀로그램에 불과할 테니까요.","JPN":"君が見ている私は、ただの短波通信で作り出されたホログラムに過ぎないでしょうから。","ENG":"For what you see in front of you is a hologram transmitted via shortwave communication.","TWN":"因為你看到的我，只不過是透過短波通訊發送的全息圖。"},"stage":{"bg":"VOID","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VOID","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"왜, 나를 찾아왔나?","JPN":"なぜ、私の前に現れた？","ENG":"Why are you talking to me?","TWN":"為什麼，來找我？"},"stage":{"bg":"VOID","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"당신이 용서받을 수도, 구원받을 수도 없는 구제불능의 죄인이기 때문입니다.","JPN":"君が許されることも、救われることもできない、救いようのない罪人だからです。","ENG":"Because you are a sinner beyond forgiveness nor salvation.","TWN":"因為你是既不能被原諒，也不無法被救贖的無可救藥之罪人。"},"stage":{"bg":"VOID","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그래서, 심판이라도 내리려고 온 건가……?","JPN":"それで、裁きにでも来たというのか……？","ENG":"So, are you here to sentence me...?","TWN":"所以，你是來審判我的嗎……？"},"stage":{"bg":"VOID","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"그렇지만 동시에 다른 누군가를 한 걸음 더 밀어 줄 수도 있는 분이죠.","JPN":"ところが、同時に君は誰かの背中を押してあげることもできる存在。","ENG":"But at the same time, you are someone who can nudge others to take the next step.","TWN":"不過同樣你也可以推別人一把。"},"stage":{"bg":"VOID","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"이제 곧 죽음을 맞이할 당신에게는 아무런 의미도 없겠지만요.","JPN":"もうすぐ死ぬ君には何の意味もないことではありますが。","ENG":"Maybe it will be meaningless as you are awaiting your inevitable death...","TWN":"即使這對於將要迎來死亡的你來說是沒有任何意義的。"},"stage":{"bg":"VOID","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VOID","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"선택은 당신의 자유입니다.","JPN":"何を選ぶかは君の自由です。","ENG":"The choice is up to you.","TWN":"怎麼選擇是你的自由。"},"stage":{"bg":"VOID","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"그저 이 말을 전해 드리고 싶었습니다.","JPN":"ただこの言葉を伝えたかったのです。","ENG":"That is all I wanted to say to you.","TWN":"我想說的就是這些了。"},"stage":{"bg":"VOID","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"도미닉 킹 레지날드.","JPN":"ドミニーク・キング・レジナルド。","ENG":"Dominic King Reginald.","TWN":"多明尼克。"},"stage":{"bg":"VOID","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VOID","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"narration","speaker":null,"text":{"KOREA":"고민할 시간은 없다.","JPN":"悩んでいる時間はない。","ENG":"There is no time to ponder.","TWN":"沒有時間考慮。"},"stage":{"bg":"VOID","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"narration","speaker":null,"text":{"KOREA":"고민할 이유도, 없다.","JPN":"悩む理由も、ない。","ENG":"Nor a reason to do so.","TWN":"也沒有理由考慮。"},"stage":{"bg":"VOID","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"시간이……. 내 생각보다 많이 흘렀나 보군.","JPN":"時間が……思ったよりもたくさん過ぎていたようだ。","ENG":"Time... A lot has passed than I thought.","TWN":"看來逝去的歲月……比我想得還要更長啊。"},"stage":{"bg":"MS_1114","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"방향은, 저쪽인가.","JPN":"方向は、あっちか。","ENG":"Is it that way?","TWN":"方向，是那邊嗎？"},"stage":{"bg":"MS_1114","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"narration","speaker":null,"text":{"KOREA":"느껴진다.","JPN":"感じる。","ENG":"I can feel them.","TWN":"感覺到了。"},"stage":{"bg":"MAINSTREAM_802","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"narration","speaker":null,"text":{"KOREA":"보이지 않을 만큼 멀리 떨어져 있지만.","JPN":"見えないぐらい遠くに離れているが。","ENG":"They are so far away that I cannot see.","TWN":"在充滿不確定性的浪濤那頭，"},"stage":{"bg":"MAINSTREAM_802","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"narration","speaker":null,"text":{"KOREA":"바로 옆에 있는 것처럼 아주 가깝게.","JPN":"すぐ隣にいるかのように。","ENG":"But I feel their presence as if she's close by.","TWN":"距離遙遠到無法望及的地方。"},"stage":{"bg":"MAINSTREAM_802","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"narration","speaker":null,"text":{"KOREA":"불확실성의 파도 너머에서.","JPN":"不確実性の波の向こうで。","ENG":"Beyond the crashing waves of uncertainty.","TWN":"但又好像就在身旁一樣，很近。"},"stage":{"bg":"MAINSTREAM_802","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"가십시오. 사령관님.","JPN":"行ってください。司令官。","ENG":"Go, Commander.","TWN":"請起程吧，司令官。"},"stage":{"bg":"MS_1114","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"제이나도. 미래도.","JPN":"ジェイナも。未来も。","ENG":"I leave everything in your hands.","TWN":"婕娜，未來，"},"stage":{"bg":"MS_1114","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 제 마지막도.","JPN":"そして私の最後も。","ENG":"With Jaina. The future.","TWN":"還有我的結局，"},"stage":{"bg":"MS_1114","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"전부… 당신에게 맡기겠습니다.","JPN":"すべて…あなたにお預けします。","ENG":"And even... my last moment.","TWN":"全都……交給你了。"},"stage":{"bg":"MS_1114","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"……언제나 그랬듯이.","JPN":"……いつもそうであったように。","ENG":"...Like I always have.","TWN":"……就像一直以來的那樣。"},"stage":{"bg":"MS_1114","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"……연산량, 한계. 더 이상은, 지속할 수 없다.","JPN":"……演算量、限界。これ以上は耐えられない。","ENG":"...Calculations at its limit. Unsustainable.","TWN":"……運算量，達到，極限，無法再繼續了。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"조, 조금만 버텨! 넘버 5!","JPN":"も、もう少し耐えて！　ナンバー5！","ENG":"H-hang in there! Number 5!","TWN":"再，再堅持一下！5號！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"그래! 다들 무지 애쓰고 있다고!!","JPN":"そうだ！　全員頑張ってるんだ！！","ENG":"Yeah! Everyone's trying really hard!!","TWN":"是啊！大家都在努力呢！！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"카일! 의무실까지 버릴 수 있는 화물들은 전부 버렸어!","JPN":"カイル！　医務室にあるものまで、捨てられるものは全部捨てたわ！","ENG":"Kyle! We threw away everything we could, including what was in the medical bay!","TWN":"凱爾！連醫務室內能丟的貨物也都丟掉了！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"죄송합니다! 내부 변수만으로는 어떻게 해도 부족해요!","JPN":"申し訳ありません！　内部の変数だけではどうしても足りません！","ENG":"I'm sorry! But no matter what we do inside, it's still not enough!","TWN":"很抱歉！光靠內部的變數無論如何也無法滿足！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"어떻게 해도……! 어떻게 해도 도약이 불가능하단 말입니다!","JPN":"どうやっても……！　どうやっても跳躍は不可能なんです！","ENG":"Whatever we do...! It's impossible to jump!","TWN":"無論如何……！無論如何都無法跳躍！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"조금이라도, 종이 한 장의 차이라도 좋으니 외부의 변수가 더해진다면……! 그러기만 한다면……!","JPN":"少しでも、紙一重でも差でもいいから外部からの変数が加われば……！　そうすれば……！","ENG":"If only... We could have some external variables...! Then maybe...!","TWN":"只要一點點，哪怕是一張紙的差別也好，一點點來自外部的變數……！只要那樣……！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"제기랄!!","JPN":"クソ！！","ENG":"Dammit!!","TWN":"可惡！！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_BIG"},{"id":"L18_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"……곤란하군요. 회장님의 지원으로 버텼지만 가르강튀아도 조만간 한계입니다.","JPN":"……困りましたね。会長の支援のおかげで耐えていましたが、ガルガンティアももうすぐ限界です。","ENG":"...This is bad. I have been able to sustain my form with Miss Shin's support, but Garguantia is at its limit.","TWN":"……情況很糟糕。雖然靠著會長的支援能維持這個形態，但加爾剛迪亞遲早也會到達極限。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"쿼드 스러스터도 이미 임계점을 넘었으니까요. 그럴지도요.","JPN":"クワッドスラスターもすでに臨界点を超えていますからね。そうかもしれません。","ENG":"Yes, and the Quad Thrusters have also exceeded their critical point.","TWN":"沒錯，四驅推進器也已經超出臨界點了。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"하지만 사령관님, 아직 기회는 남아 있을 거예요.","JPN":"でも司令官、まだチャンスはあるはずです。","ENG":"But Commander, I am sure there is still a chance.","TWN":"不過司令官，我們還有機會。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"기회라니요?","JPN":"チャンスとは？","ENG":"A chance?","TWN":"機會？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"어……?","JPN":"あ……？","ENG":"Huh...?","TWN":"呃……？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"자, 잠깐! 선체에 외력이 가해지고 있어!","JPN":"ま、待って！　船体に外力が加わっているわ！","ENG":"W-wait! There's an external force being applied to the ship!","TWN":"等，等等！船體正受到外力作用！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"외력이라니 무슨 말씀이십니까? 허수 공간에 어떻게……!","JPN":"外力なんてどういうことですか？　虚数空間にそんな……！","ENG":"What do you mean? How is that possible in the imaginary space...?!","TWN":"外力？你在說什麼？虛數空間怎麼會……！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"바람이에요!","JPN":"風です！","ENG":"It's wind!","TWN":"是風！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L27_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"바람이라니? 허수 공간에서 말인가?","JPN":"風だと？　虚数空間にか？","ENG":"Wind? In here?","TWN":"風？在虛數空間裡嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"사실입니다, 사령관님! 바람이 불고 있습니다!","JPN":"本当です、司令官！　風が吹いています！","ENG":"It's true, Commander! A gust of wind is blowing!","TWN":"是真的，司令官！外面起風了！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"사령관님, 외부 변수에요!","JPN":"司令官、外部変数です！","ENG":"Commander, this is the external variable!","TWN":"司令官，這正是我們所需的外部變數！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"그렇다면……!","JPN":"ならば……！","ENG":"Then...!","TWN":"這樣的話……！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"실비아! 스러스터가 파열되어도 상관없다! 마지막으로 최대 출력까지 올려라!","JPN":"シルビア！　スラスターが破裂しても構わない！　これが最後だ、最大まで出力を上げろ！","ENG":"Sylvia! I don't care if the thrusters get destroyed! Max out their output!","TWN":"希爾維亞！就算推進器損毀也沒有關係！現在加到最大輸出！"},"stage":{"bg":"MS_1109","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"카일, 상황은?","JPN":"カイル、状況は？","ENG":"Kyle, what is the situation?","TWN":"凱爾，情況怎麼樣？"},"stage":{"bg":"MS_1109","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"조금…… 정말 조금이지만……!","JPN":"少し……ほんの少しだけですが……！","ENG":"It's... It's small, but...!","TWN":"雖然……只是一點點……！"},"stage":{"bg":"MS_1109_1","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"차원계면의 균열을 확인했습니다! 가능합니다!","JPN":"次元界面の亀裂を確認しました！　行けます！","ENG":"A rift in the Dimension Surface has been confirmed! We're good to go!","TWN":"但確認到次元界面的裂縫了！可以！"},"stage":{"bg":"MS_1109_1","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L43_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"큭……! 그렇다면야 남은 건 기합이야!","JPN":"くっ……！　ならばあとは気合よ！","ENG":"Kgh...! Then all that's left is to pray!","TWN":"咳……！那其餘的就看運氣了！"},"stage":{"bg":"MS_1109_1","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"버틸 만큼 버텼으면 이제 부서져 버리라고!!!","JPN":"十分に耐えたわ、もう壊れちゃえ！！！","ENG":"Give it all you've got! Go through it! GO!","TWN":"壞掉就壞掉吧，現在就加到最大輸出！！！"},"stage":{"bg":"MS_1109_1","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};